"use client";

import { useEffect, useMemo, useState } from "react";
import Plantilla1Static from "./plantillas/Plantilla1Static";
import Plantilla2Static from "./plantillas/Plantilla2Static";
import Plantilla3Static from "./plantillas/Plantilla3Static";
import Plantilla4Static from "./plantillas/Plantilla4Static";

export default function PagoFastCashStatic({
  token,
  tipoPlantilla = "1",
}: {
  token: string;
  tipoPlantilla?: string;
}) {
  const [data, setData] = useState<any>(null);
  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  const origin = useMemo(() => {
    if (typeof window === "undefined") return "";
    return window.location.origin;
  }, []);

  async function copyToClipboard(text: string) {
    await navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 1200);
  }

  useEffect(() => {
    if (!token) return;

    (async () => {
      try {
        const res = await fetch(`/api/plantillas-temporales-3/${token}`, {
          cache: "no-store",
        });

        const json = await res.json();
        const payload = json?.data ?? json;

        setData(payload);
      } catch {
        setError("Error cargando datos");
      }
    })();
  }, [token]);

  if (error) return <div className="text-white">{error}</div>;
  if (!data) return <div className="text-white">Cargando...</div>;

  const props = {
    data,
    origin,
    copied,
    onCopy: copyToClipboard,
  };

  switch (tipoPlantilla) {
    case "2":
      return <Plantilla2Static {...props} />;
    case "3":
      return <Plantilla3Static {...props} />;
    case "4":
      return <Plantilla4Static {...props} />;
    default:
      return <Plantilla1Static {...props} />;
  }
}